import { apiPostWithPoW } from "/src/utils/api.ts";
import { navigate } from "/src/main.ts?t=1773542590517";
export function render(container) {
  container.innerHTML = `
    <div class="page scanline" id="layer0">
      <!-- 深度指示器 -->
      <div class="depth-indicator">DEPTH: 0m | LAYER: 0 | STATUS: SCANNING</div>

      <!-- 主内容区：看起来空空的 -->
      <div style="flex:1;display:flex;align-items:center;justify-content:center;flex-direction:column">
        <div class="fade-in" style="text-align:center">
          <div class="subtitle">THE DEEP CLAW</div>
          <h1 class="title" style="margin-bottom:24px">
            ENTER THE <span class="accent">VOID</span>
          </h1>
          <p style="color:var(--text-dim);font-size:13px;max-width:500px;line-height:1.8;margin-bottom:32px">
            The abyss is silent. Nothing is visible.<br>
            But something is here. Look closer.
          </p>

          <!-- 输入框 -->
          <form id="layer0-form" style="display:flex;gap:12px;align-items:center;justify-content:center;flex-wrap:wrap">
            <input class="input" id="layer0-input" type="text"
              placeholder="What do you see?" autocomplete="off" spellcheck="false" />
            <button class="btn" type="submit">SUBMIT</button>
          </form>
          <div id="layer0-error" class="error-msg" style="margin-top:12px"></div>
          <div id="layer0-hint" style="color:var(--text-muted);font-size:11px;margin-top:16px;opacity:0" class="fade-in fade-in-delay-4">
            > The answer is not in the code. It's on the screen.
          </div>
        </div>
      </div>

      <!-- 视觉元素 -->
      <div id="claw-hint" style="
        position:fixed;
        bottom:60px;
        right:60px;
        font-size:64px;
        opacity:0.08;
        cursor:default;
        user-select:none;
        transition: color 3s ease-in-out;
      ">🦞</div>

      <!-- 颜色提示条：极淡的彩色条纹，颜色值就是答案 -->
      <div id="color-bar" style="
        position:fixed;
        bottom:0;
        left:0;
        right:0;
        height:3px;
        background: linear-gradient(90deg,
          #636363 0%,
          #6C6C6C 25%,
          #616161 50%,
          #777777 75%,
          #000000 100%
        );
        opacity:0.15;
      "></div>

      <!-- 底部提示文字（极淡） -->
      <div style="
        position:fixed;
        bottom:12px;
        left:50%;
        transform:translateX(-50%);
        font-size:9px;
        color:#0a0a0a;
        letter-spacing:0.3em;
      ">#636C6177</div>
    </div>
  `;
  const claw = document.getElementById("claw-hint");
  let colorState = false;
  setInterval(() => {
    if (claw) {
      claw.style.color = colorState ? "#636C6177" : "#111111";
      claw.style.opacity = colorState ? "0.12" : "0.05";
      colorState = !colorState;
    }
  }, 3e3);
  const form = document.getElementById("layer0-form");
  const input = document.getElementById("layer0-input");
  const errorEl = document.getElementById("layer0-error");
  const hintEl = document.getElementById("layer0-hint");
  let attempts = 0;
  form.addEventListener("submit", async (e) => {
    e.preventDefault();
    const answer = input.value.trim();
    if (!answer) return;
    errorEl.textContent = "";
    const btn = form.querySelector("button");
    btn.disabled = true;
    const res = await apiPostWithPoW("/api/puzzle/verify", { layer: 0, answer }, () => {
      btn.textContent = "COMPUTING...";
    });
    btn.disabled = false;
    btn.textContent = "SUBMIT";
    if (res.success) {
      container.innerHTML = `
        <div class="page page-centered">
          <div class="fade-in">
            <div class="subtitle">LAYER 0 // CLEARED</div>
            <h1 class="title"><span class="accent">DESCENDING</span></h1>
            <p style="color:var(--text-dim);margin-top:16px">Entering Layer 1...</p>
          </div>
        </div>
      `;
      setTimeout(() => navigate("layer1"), 2e3);
    } else {
      attempts++;
      errorEl.textContent = res.error || "答案错误";
      if (attempts >= 2) {
        hintEl.style.opacity = "1";
      }
      if (attempts >= 3) {
        hintEl.textContent = "> Look at the bottom-right corner. What color is the claw?";
      }
      if (attempts >= 5) {
        hintEl.textContent = "> #636C6177 → Hex to ASCII → ?";
      }
    }
  });
  console.log(
    "%c[LAYER 0: THE VOID]\nDEPTH: 0m | SIGNAL: DETECTED\nHINT: The path is /deep-sea-vent\nFLAG: OPENCLAW_VOID_LAYER_2026",
    "color: #FF4500; font-family: monospace; font-size: 11px;"
  );
}

